@import "tailwindcss";
@import "tw-animate-css";
@import "../styles/theme.css";
@import "../styles/rtl.css";
@import "../styles/dashboard.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --font-sans: var(--font-cairo), var(--font-inter), system-ui, sans-serif;
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
  }
  /* Smooth scrolling */
  html {
    scroll-behavior: smooth;
  }
  /* Custom scrollbar */
  ::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  ::-webkit-scrollbar-track {
    @apply bg-transparent;
  }
  ::-webkit-scrollbar-thumb {
    @apply rounded-full bg-muted-foreground/30;
  }
  ::-webkit-scrollbar-thumb:hover {
    @apply bg-muted-foreground/50;
  }
}

/* ============================================
   Review Studio — Social Preview Animations
   ============================================ */

@layer utilities {
  /* Music title marquee scroll */
  @keyframes marquee {
    0% { transform: translateX(0); }
    100% { transform: translateX(-100%); }
  }
  .animate-marquee {
    animation: marquee 8s linear infinite;
  }

  /* Double-tap heart burst */
  @keyframes heart-burst {
    0% { transform: scale(0) rotate(-15deg); opacity: 0; }
    15% { transform: scale(1.3) rotate(-15deg); opacity: 1; }
    30% { transform: scale(1) rotate(-15deg); opacity: 1; }
    70% { transform: scale(1.05) rotate(-15deg); opacity: 1; }
    100% { transform: scale(1.2) rotate(-15deg); opacity: 0; }
  }
  .animate-heart-burst {
    animation: heart-burst 800ms ease-out forwards;
  }

  /* Video slide transitions for swipe navigation */
  @keyframes slide-up-out {
    0% { transform: translateY(0); opacity: 1; }
    100% { transform: translateY(-100%); opacity: 0; }
  }
  @keyframes slide-up-in {
    0% { transform: translateY(100%); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
  }
  @keyframes slide-down-out {
    0% { transform: translateY(0); opacity: 1; }
    100% { transform: translateY(100%); opacity: 0; }
  }
  @keyframes slide-down-in {
    0% { transform: translateY(-100%); opacity: 0; }
    100% { transform: translateY(0); opacity: 1; }
  }
  .animate-slide-up-out { animation: slide-up-out 300ms ease-in-out forwards; }
  .animate-slide-up-in { animation: slide-up-in 300ms ease-in-out forwards; }
  .animate-slide-down-out { animation: slide-down-out 300ms ease-in-out forwards; }
  .animate-slide-down-in { animation: slide-down-in 300ms ease-in-out forwards; }

  /* Generic fade-in for skeleton → content */
  @keyframes fade-in {
    0% { opacity: 0; }
    100% { opacity: 1; }
  }
  .animate-fade-in {
    animation: fade-in 400ms ease-out forwards;
  }

  /* Skeleton shimmer */
  @keyframes shimmer {
    0% { background-position: -200% 0; }
    100% { background-position: 200% 0; }
  }
  .animate-shimmer {
    background: linear-gradient(
      90deg,
      rgba(255, 255, 255, 0.04) 25%,
      rgba(255, 255, 255, 0.08) 50%,
      rgba(255, 255, 255, 0.04) 75%
    );
    background-size: 200% 100%;
    animation: shimmer 1.5s ease-in-out infinite;
  }

  /* Hold-to-speed indicator pulse */
  @keyframes speed-pulse {
    0%, 100% { transform: scale(1); opacity: 0.9; }
    50% { transform: scale(1.08); opacity: 1; }
  }
  .animate-speed-pulse {
    animation: speed-pulse 800ms ease-in-out infinite;
  }

  /* Floating animation for empty state illustrations */
  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-6px); }
  }
  .animate-float {
    animation: float 3s ease-in-out infinite;
  }

  /* UI hide/show transition for auto-hide */
  @keyframes ui-fade-out {
    0% { opacity: 1; transform: translateY(0); }
    100% { opacity: 0; transform: translateY(-8px); pointer-events: none; }
  }
  @keyframes ui-fade-in {
    0% { opacity: 0; transform: translateY(-8px); }
    100% { opacity: 1; transform: translateY(0); }
  }
  .ui-hidden {
    opacity: 0;
    transform: translateY(-8px);
    pointer-events: none;
    transition: opacity 300ms ease, transform 300ms ease;
  }
  .ui-visible {
    opacity: 1;
    transform: translateY(0);
    pointer-events: auto;
    transition: opacity 300ms ease, transform 300ms ease;
  }
}

